// ================================================================
// STAGE 1: MONITORING CONFIGURATION ENGINE
// Define sources, keywords, weights, thresholds
// ================================================================

const config = {
  run_id: 'INTEL-' + Date.now(),
  started_at: new Date().toISOString(),

  // RSS feeds to monitor (different categories)
  feeds: [
    {
      name: 'HackerNews',
      url: 'https://hnrss.org/newest?points=50&count=20',
      category: 'developer_community',
      weight: 1.5
    },
    {
      name: 'TechCrunch',
      url: 'https://techcrunch.com/feed/',
      category: 'startup_news',
      weight: 1.2
    },
    {
      name: 'The Verge',
      url: 'https://www.theverge.com/rss/index.xml',
      category: 'tech_general',
      weight: 1.0
    }
  ],

  // Keyword groups with weights
  keyword_groups: {
    direct_competitors: {
      keywords: ['n8n', 'zapier', 'make.com', 'integromat', 'workato', 'tray.io'],
      weight: 3.0,
      alert_on_match: true
    },
    core_technology: {
      keywords: ['workflow automation', 'automation platform', 'integration platform', 'iPaaS'],
      weight: 2.5,
      alert_on_match: false
    },
    ai_trends: {
      keywords: ['ai agent', 'langchain', 'rag', 'vector database', 'llm', 'openai', 'anthropic', 'ai orchestration'],
      weight: 2.0,
      alert_on_match: false
    },
    market_signals: {
      keywords: ['no-code', 'low-code', 'api integration', 'business automation', 'process automation'],
      weight: 1.5,
      alert_on_match: false
    },
    funding_signals: {
      keywords: ['series a', 'series b', 'raised', 'funding', 'acquisition', 'acquired'],
      weight: 1.8,
      alert_on_match: false
    }
  },

  // Thresholds
  min_relevance_score: 2.0,
  max_articles_output: 10,
  dedup_title_similarity: 0.7
};

return [{ json: config }];

// Split config into individual feed tasks
const config = $input.first().json;
return config.feeds.map(feed => ({
  json: {
    ...feed,
    keyword_groups: config.keyword_groups,
    min_relevance_score: config.min_relevance_score,
    run_id: config.run_id
  }
}));

// ================================================================
// STAGE 2: NLP KEYWORD ENGINE
// Multi-group keyword matching with weighted scoring
// Title matches get 3x weight, body matches 1x
// Group weights multiply the base score
// ================================================================

const articles = $input.all();
const feedInfo = $('3. Split Into Feeds').first().json;
const groups = feedInfo.keyword_groups;
const minScore = feedInfo.min_relevance_score;

const results = [];

for (const article of articles) {
  const a = article.json;
  if (!a.title) continue;

  const title = (a.title || '').toLowerCase();
  const body = (a.contentSnippet || a.description || a.content || '').toLowerCase();
  const fullText = title + ' ' + body;

  let totalScore = 0;
  const matchedGroups = [];
  const allKeywords = [];
  let hasAlertKeyword = false;

  // Check each keyword group
  for (const [groupName, group] of Object.entries(groups)) {
    const groupMatches = [];

    for (const keyword of group.keywords) {
      const kw = keyword.toLowerCase();
      if (!fullText.includes(kw)) continue;

      // Title match = 3x, body match = 1x
      let matchScore = 1.0;
      if (title.includes(kw)) matchScore = 3.0;

      // Apply group weight
      matchScore *= group.weight;

      // Apply feed weight
      matchScore *= feedInfo.weight;

      totalScore += matchScore;
      groupMatches.push(keyword);
      allKeywords.push(keyword);

      if (group.alert_on_match) hasAlertKeyword = true;
    }

    if (groupMatches.length > 0) {
      matchedGroups.push({
        group: groupName,
        keywords: groupMatches,
        count: groupMatches.length
      });
    }
  }

  // Skip if below threshold
  if (totalScore < minScore) continue;

  results.push({
    title: a.title,
    link: a.link || a.guid || '#',
    source: feedInfo.name,
    source_category: feedInfo.category,
    published: a.pubDate || a.isoDate || null,
    snippet: body.slice(0, 200),
    relevance_score: Math.round(totalScore * 100) / 100,
    matched_keywords: allKeywords,
    matched_groups: matchedGroups,
    has_competitor_mention: hasAlertKeyword,
    keyword_count: allKeywords.length,
    run_id: feedInfo.run_id
  });
}

// Sort by relevance
results.sort((a, b) => b.relevance_score - a.relevance_score);

if (results.length === 0) {
  return [{ json: { empty: true, source: feedInfo.name, run_id: feedInfo.run_id } }];
}

return results.map(r => ({ json: r }));

// ================================================================
// STAGE 3: AGGREGATION & DEDUPLICATION
// Merge results from all feeds, deduplicate, compute stats
// ================================================================

const allItems = $input.all().map(i => i.json);

// Filter out empty feed results
const articles = allItems.filter(a => !a.empty);

if (articles.length === 0) {
  return [{ json: {
    status: 'no_matches',
    total_scanned: allItems.length,
    message: 'No articles matched keywords in this scan cycle.',
    timestamp: new Date().toISOString()
  }}];
}

// Deduplication by title similarity
const unique = [];
const seenTitles = [];

for (const article of articles) {
  const titleLower = article.title.toLowerCase();
  const words = titleLower.split(/\s+/).filter(w => w.length > 3);

  // Check against already seen titles
  let isDuplicate = false;
  for (const seen of seenTitles) {
    const overlap = words.filter(w => seen.includes(w)).length;
    const similarity = overlap / Math.max(words.length, 1);
    if (similarity > 0.6) {
      isDuplicate = true;
      break;
    }
  }

  if (!isDuplicate) {
    unique.push(article);
    seenTitles.push(titleLower);
  }
}

// Sort by relevance and take top 10
unique.sort((a, b) => b.relevance_score - a.relevance_score);
const top = unique.slice(0, 10);

// Compute analytics
const kwFrequency = {};
const groupFrequency = {};
const sourceCount = {};
let competitorMentions = 0;

top.forEach(a => {
  a.matched_keywords.forEach(kw => { kwFrequency[kw] = (kwFrequency[kw] || 0) + 1; });
  a.matched_groups.forEach(g => { groupFrequency[g.group] = (groupFrequency[g.group] || 0) + g.count; });
  sourceCount[a.source] = (sourceCount[a.source] || 0) + 1;
  if (a.has_competitor_mention) competitorMentions++;
});

const topKeywords = Object.entries(kwFrequency)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 8)
  .map(([kw, count]) => ({ keyword: kw, mentions: count }));

const topGroups = Object.entries(groupFrequency)
  .sort((a, b) => b[1] - a[1])
  .map(([group, count]) => ({ group, mentions: count }));

return [{ json: {
  articles: top,
  analytics: {
    total_scanned: allItems.length,
    total_matched: articles.length,
    after_dedup: unique.length,
    returned: top.length,
    competitor_mentions: competitorMentions,
    top_keywords: topKeywords,
    group_breakdown: topGroups,
    source_distribution: sourceCount,
    avg_relevance: Math.round(top.reduce((s, a) => s + a.relevance_score, 0) / top.length * 100) / 100
  },
  timestamp: new Date().toISOString()
}}];

// Build AI analysis prompt from aggregated data
const data = $input.first().json;
const articles = data.articles;
const analytics = data.analytics;

const articleList = articles.map((a, i) => 
  (i + 1) + '. [' + a.source + '] "' + a.title + '"' +
  '\n   Keywords: ' + a.matched_keywords.join(', ') +
  '\n   Relevance: ' + a.relevance_score +
  (a.has_competitor_mention ? ' ⚠️ COMPETITOR MENTION' : '')
).join('\n\n');

const prompt = 'You are a senior competitive intelligence analyst for a workflow automation company competing with Zapier and Make.com.\n\n' +
  'Analyze these ' + articles.length + ' articles from the last 12 hours:\n\n' +
  articleList + '\n\n' +
  'Analytics: ' + analytics.competitor_mentions + ' competitor mentions, ' +
  'top keywords: ' + analytics.top_keywords.map(k => k.keyword + '(' + k.mentions + ')').join(', ') + '\n\n' +
  'Provide your analysis in this exact format:\n' +
  'MARKET TRENDS (2-3 bullet points)\n' +
  'COMPETITIVE MOVES (any competitor activity detected)\n' +
  'OPPORTUNITIES (actionable business opportunities)\n' +
  'THREAT LEVEL: LOW/MEDIUM/HIGH (with 1 sentence why)\n\n' +
  'Be specific. Reference article numbers. No generic observations.';

return [{ json: { ...data, ai_prompt: prompt } }];

