// ================================================================
// STAGE 4: BUILD EXECUTIVE INTELLIGENCE BRIEFING
// Combines analytics + AI analysis + article links
// ================================================================
const data = $('9. Build Analysis Prompt').first().json;
const aiRaw = $input.first().json;
const articles = data.articles;
const stats = data.analytics;
let aiAnalysis = 'AI analysis unavailable for this cycle.';
try { aiAnalysis = aiRaw.choices[0].message.content; } catch(e) {}
// Format date
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toISOString().split('T')[1].slice(0, 5);
// Build article links
const articleLinks = articles.slice(0, 8).map((a, i) => {
  const score = a.relevance_score;
  const flag = a.has_competitor_mention ? ' !!' : '';
  return (i + 1) + '. ' + a.source + ' - ' + a.title.slice(0, 55) + flag + '\n   Score: ' + score + ' - ' + a.matched_keywords.slice(0, 3).join(', ');
}).join('\n');
// Build keyword heatmap
const kwHeat = stats.top_keywords.map(k => k.keyword + ' ' + k.mentions).join(' | ');
// Build group breakdown
const groupBreak = stats.group_breakdown.map(g => g.group.replace(/_/g, ' ') + ': ' + g.mentions).join(' | ');
const briefing = [
  'COMPETITIVE INTELLIGENCE BRIEFING',
  dateStr + ' ' + timeStr + ' UTC',
  '',
  'SCAN METRICS',
  '  Sources scanned: ' + Object.keys(stats.source_distribution).length,
  '  Articles matched: ' + stats.total_matched + ' After dedup: ' + stats.after_dedup,
  '  Competitor mentions: ' + stats.competitor_mentions,
  '  Avg relevance: ' + stats.avg_relevance,
  '',
  'KEYWORD HEATMAP',
  '  ' + kwHeat,
  '',
  'GROUP BREAKDOWN',
  '  ' + groupBreak,
  '',
  'AI STRATEGIC ANALYSIS',
  '',
  aiAnalysis,
  '',
  'TOP ARTICLES',
  '',
  articleLinks,
  '',
  'Automated by n8n Intelligence Pipeline v2.0'
].join('\n');
// Clean special characters that break Telegram
const clean = briefing.replace(/[_*\[\]()~`>#+\-=|{}.!]/g, function(match) {
  if (match === '-' || match === '.') return match;
  return ' ';
}).slice(0, 4000);
return [{ json: {
  notification: clean,
  analytics: stats,
  ai_analysis: aiAnalysis,
  article_count: articles.length
}}];

// ================================================================
// STAGE 5: COMPETITOR ALERT CHECK
// If any competitor was mentioned, send separate urgent alert
// ================================================================

const data = $('9. Build Analysis Prompt').first().json;
const competitorArticles = data.articles.filter(a => a.has_competitor_mention);

if (competitorArticles.length === 0) {
  return [{ json: { has_competitor_alert: false } }];
}

const alertLines = [
  '⚠️ COMPETITOR ALERT ⚠️',
  '',
  competitorArticles.length + ' article(s) mention direct competitors:',
  ''
];

competitorArticles.forEach((a, i) => {
  alertLines.push((i + 1) + '. ' + a.title);
  alertLines.push('   Source: ' + a.source + ' | Keywords: ' + a.matched_keywords.join(', '));
  alertLines.push('   Link: ' + a.link);
  alertLines.push('');
});

alertLines.push('Action: Review and assess competitive impact.');

return [{ json: {
  has_competitor_alert: true,
  competitor_notification: alertLines.join('\n'),
  competitor_count: competitorArticles.length
}}];

// EXECUTION LOG
const stats = $('11. Build Executive Brief').first().json.analytics || {};
return [{ json: {
  event: 'intelligence_scan_complete',
  articles_found: stats.total_matched || 0,
  after_dedup: stats.after_dedup || 0,
  competitor_mentions: stats.competitor_mentions || 0,
  avg_relevance: stats.avg_relevance || 0,
  sources_scanned: Object.keys(stats.source_distribution || {}).length,
  timestamp: new Date().toISOString()
}}];
